import{_ as a,o,i as s,aZ as t}from"./chunks/framework.D08fXB_e.js";const h=JSON.parse('{"title":"私有 Storage 数据&#x20;","description":"","frontmatter":{},"headers":[],"relativePath":"guide/storage.md","filePath":"guide/storage.md"}'),i={name:"guide/storage.md"};function r(n,e,d,l,c,g){return o(),s("div",null,[...e[0]||(e[0]=[t(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /guide/storage.md for this page in Markdown format</div><h1 id="私有-storage-数据-x20" tabindex="-1">私有 Storage 数据 <a class="header-anchor" href="#私有-storage-数据-x20" aria-label="Permalink to “私有 Storage 数据&amp;#x20;”">​</a></h1><p>由于 localStorage 和 sessionStorage 的同源策略，同一域名下的 storage 数据会共享。如果你恰好需要在同一域名下部署两套(及以上)系统，不可避免会出现 storage 数据冲突，框架提供了一个 storage 类来解决这个问题。</p><p>解决同源 storage 数据冲突的方式就是增加前缀区分。</p><p>首先需要在环境变量中设置一个唯一且不重名的前缀：</p><div class="language-env"><button title="Copy Code" class="copy"></button><span class="lang">env</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># localStorage/sessionStorage 前缀</span></span>
<span class="line"><span># localStorage/sessionStorage prefix</span></span>
<span class="line"><span>VITE_APP_STORAGE_PREFIX = oc_</span></span></code></pre></div><p>然后就可以继续使用 <code>localStorage</code> 和 <code>sessionStorage</code> 了，框架重写了 <code>localStorage</code> 和 <code>sessionStorage</code> ，所以使用方式和原来一样，并且还增加了 2 个 API：</p><ul><li><code>localStorage.has(key)</code> / <code>sessionStorage.has(key)</code> 判断对象是否存在</li><li><code>localStorage.length</code> / <code>sessionStorage.length</code> 获取对象数量（只统计带前缀的 key）</li></ul>`,8)])])}const _=a(i,[["render",r]]);export{h as __pageData,_ as default};
